// Get data from previous node (publisher/member data)
const previousNodeData = $input.all().map(item => item.json);

// Get data from "GAME FOUND IN MADMIN" node (game data)
const gameFoundData = $('GAME FOUND IN MADMIN').all().map(item => item.json);

// Process and match
const results = [];

for (const record of previousNodeData) {
  const productId = record.product_id;

  // Find matching game where id === product_id
  const matchedGame = gameFoundData.find(game => game.id === productId);

  if (matchedGame) {
    // Append game_name from matched game's name
    results.push({
      json: {
        ...record,
        game_name: matchedGame.name
      }
    });
  } else {
    // No match found — pass through without game_name (or skip if preferred)
    results.push({
      json: {
        ...record,
        game_name: null
      }
    });
  }
}

return results;

// Get all items from the node "LOOP THRU GAME"
const data = $('LOOP THRU GAME').all();

// Add message field to each item
return data.map(item => {
  return {
    json: {
      ...item.json,
      message: "this game name is not found both madmin and steam"
    }
  };
});

// Get data from previous node (user/org data)
const previousNodeData = $input.all().map(item => item.json);

// Get data from "STEAM NECESSARY FIELDS" node
const steamFieldsData = $('STEAM NECESSARY FIELDS').all().map(item => item.json);

// Merge records where steam_appid matches
const mergedResults = [];

for (const user of previousNodeData) {
  const matchingSteam = steamFieldsData.find(
    steam => steam.steam_appid === user.steam_appid
  );

  if (matchingSteam) {
    mergedResults.push({
      steam_appid: user.steam_appid,
      game_name: matchingSteam.game_name,
      organisations_name: user.organisations_name,
      role: user.role,
      user_id: user.user_id,
      email: user.email,
      first_name: user.first_name,
      last_name: user.last_name,
    });
  }
}

// Return as n8n items
return mergedResults.map(item => ({ json: item }));

// Get data from previous node (contact list results)
const currentNodeData = $input.all();
const intercomLoopData = $('INTERCOM LOOP').all();
const organisationNames = intercomLoopData.map(item => item.json.organisation_name);

// Flatten all contacts
const allContacts = [];
for (const item of currentNodeData) {
  const json = item.json;
  const lists = Array.isArray(json) ? json : [json];
  for (const list of lists) {
    const contacts = list.data || [];
    for (const contact of contacts) {
      allContacts.push(contact);
    }
  }
}

// Track which orgs got matched
const matchedOrgs = new Set();
const results = [];

for (const contact of allContacts) {
  const externalId = contact.external_id || '';
  const email = contact.email || null;
  const name = contact.name || null;
  const role = contact.role || null;
  const publishers = (contact.custom_attributes?.Publishers || '').toLowerCase();
  const developers = (contact.custom_attributes?.Developers || '').toLowerCase();

  if (!externalId.startsWith('p_')) continue;

  let matchedOrg = null;
  for (const orgName of organisationNames) {
    const orgLower = orgName.toLowerCase();
    if (orgLower === publishers || orgLower === developers) {
      matchedOrg = orgName;
      break;
    }
  }

  if (matchedOrg) {
    matchedOrgs.add(matchedOrg); // track it
    results.push({
      json: {
        organisation_name: matchedOrg,
        externalId,
        email,
        name,
        role,
        hasFound: true,
      }
    });
  }
}

// After the loop, push any orgs that were never matched
for (const orgName of organisationNames) {
  if (!matchedOrgs.has(orgName)) {
    results.push({
      json: {
        organisation_name: orgName,
        hasFound: false,
      }
    });
  }
}

return results;

// Get all items from previous node
const items = $input.all();

// Filter items:
// - has "hasFound" field
// - hasFound is false
const filtered = items.filter(item => 
  item.json.hasOwnProperty('hasFound') && item.json.hasFound === false
);

// Add source field to each filtered item
const result = filtered.map(item => ({
  json: {
    ...item.json,
    source: "intercom"
  }
}));

// Return filtered results
return result;

// Get data from previous node (organizations search results)
const previousData = $input.all();

// Get data from AC LOOP node
const acLoopData = $('AC LOOP').all();

const results = [];

for (let i = 0; i < acLoopData.length; i++) {
  const organisation_name = acLoopData[i].json.organisation_name;
  const organizations = previousData[i].json.organizations || [];

  // Check for EXACT match among all organizations in this result
  const exactMatch = organizations.find(org => org.name === organisation_name);

  if (exactMatch) {
    results.push({
      json: {
        ...exactMatch,
        organisation_name,
        hasFound: true
      }
    });
  } else {
    results.push({
      json: {
        organisation_name,
        hasFound: false
      }
    });
  }
}

return results;

// Get data from the previous node (accountContacts data)
const accountContactsData = $input.all();

// Get data from the "AC IMPORTANT FIELD" node (accounts data)
const accountsData = $('AC IMPORTANT FIELD').all();

const results = [];

for (const accountItem of accountsData) {
  const account = accountItem.json;
  const accountId = account.id;

  // Find matching entry in accountContacts data
  const matchingEntry = accountContactsData.find(item => {
    const contacts = item.json.accountContacts;
    // Check if any contact in this entry has account === accountId
    return Array.isArray(contacts) && contacts.some(c => c.account === accountId);
  });

  if (!matchingEntry) {
    // No match found OR accountContacts is empty — return name + flag
    results.push({
      json: {
        name: account.organisation_name,
        id: accountId,
        isAccountContactsEmpty: true
      }
    });
    continue;
  }

  const contacts = matchingEntry.json.accountContacts;
  const isEmpty = !Array.isArray(contacts) || contacts.length === 0;

  if (isEmpty) {
    results.push({
      json: {
        id: accountId,
        name: account.organisation_name,
        isAccountContactsEmpty: true
      }
    });
  } else {
    // Return the full accountContacts array with the flag
    results.push({
      json: {
        ...matchingEntry.json,
        accountName: account.organisation_name,
        isAccountContactsEmpty: false
      }
    });
  }
}

return results;

// Get all input data
const items = $input.all();

const output = [];

for (const item of items) {
  const accountName = item.json.accountName;
  const contacts = item.json.accountContacts || [];

  for (const contact of contacts) {
    output.push({
      json: {
        accountName,
        ...contact
      }
    });
  }
}

return output;

// Get all items from previous node
const items = $input.all();

// Filter items:
// - has "hasFound" field
// - hasFound is false
const filtered = items.filter(item => 
  item.json.hasOwnProperty('hasFound') && item.json.hasFound === false
);

// Add source field to each filtered item
const result = filtered.map(item => ({
  json: {
    ...item.json,
    source: "active campaign"
  }
}));

// Return filtered results
return result;

const intercomItems = $('INTERCOM: PUBLISHER NOT FOUND').all();
const acItems = $('AC: PUBLISHER NOT FOUND').all();
const results = [];

const processItem = (item) => {
  const orgName = item.json.organisation_name;
  if (!orgName) return;

  results.push({
    json: {
      ...item.json,
      organisation_name: orgName.trim(),
    }
  });
};

intercomItems.forEach(processItem);
acItems.forEach(processItem);
return results;

