const items = $input.all();

// Extract raw data
const records = items.map(item => item.json);

// Group by organisation_name
const grouped = {};

for (const record of records) {
  const key = record.organisation_name.trim().toUpperCase();

  if (!grouped[key]) {
    grouped[key] = { ...record };
  } else {
    // Duplicate found — merge sources
    const existingSource = grouped[key].source;
    const newSource = record.source;

    if (existingSource !== newSource) {
      grouped[key].source = "both";
    }

    // Merge hasFound — true wins
    grouped[key].hasFound = grouped[key].hasFound || record.hasFound;
  }
}

// Return as n8n items
return Object.values(grouped).map(record => ({ json: record }));

// Get previous node data (the main dataset)
const previousData = $input.all().map(item => item.json);

// Get the "ROW_NUMBER EXIST" node data
const rowNumberData = $('ROW_NUMBER EXIST').all().map(item => item.json);

// Normalize string for comparison: lowercase + collapse spaces
function normalize(str) {
  if (!str) return '';
  return str.toLowerCase().replace(/\s+/g, ' ').trim();
}

// Build a lookup map from the ROW_NUMBER EXIST data keyed by normalized name
const rowNumberMap = {};
for (const row of rowNumberData) {
  const key = normalize(row.name);
  rowNumberMap[key] = row;
}

// For each item in previous data, find a match and append fields
const results = [];

for (const item of previousData) {
  const gameKey = normalize(item.game_name);
  const match = rowNumberMap[gameKey];

  if (match) {
    results.push({
      ...item,
      row_number: match.row_number,
      url: match.url,
      scraped_at: match.scraped_at,
      source: match.source,
    });
  } else {
    // No match found — still include the item, matched fields will be undefined
    results.push({ ...item });
  }
}

return results.map(item => ({ json: item }));

// Get previous node data (array of users with steam_appid)
const previousNodeData = $input.all().map(item => item.json);

// Get "GET FIRST ITEM IN ARRAY" node data
const firstItemArray = $('GET FIRST ITEM IN ARRAY').all().map(item => item.json);

// Build a lookup map from the sheet data: id -> game_name_from_sheet
const sheetLookup = {};
for (const sheetItem of firstItemArray) {
  sheetLookup[sheetItem.id] = sheetItem.game_name_from_sheet;
}

// Map over each user row, match steam_appid with id, inject game_name_from_sheet
const output = [];

for (const user of previousNodeData) {
  const game_name_from_sheet = sheetLookup[user.steam_appid];

  if (game_name_from_sheet !== undefined) {
    output.push({
      json: {
        game_name_from_sheet,
        ...user
      }
    });
  }
}

return output;

// Get previous node data (game users)
const previousNodeData = $input.all().map(item => item.json);

// Get ROW_NUMBER EXIST node data
const rowNumberExistData = $('ROW_NUMBER EXIST').all().map(item => item.json);

const results = [];

for (const gameUser of previousNodeData) {
  const { game_name_from_sheet } = gameUser;

  // Find matching row in ROW_NUMBER EXIST by name field
  const matchedRow = rowNumberExistData.find(
    row => row.name === game_name_from_sheet
  );

  if (matchedRow) {
    results.push({
      json: {
        game_name_from_sheet: gameUser.game_name_from_sheet,
        url: matchedRow.url,
        source: matchedRow.source,
        steam_appid: gameUser.steam_appid,
        game_name: gameUser.game_name,
        organisations_name: gameUser.organisations_name,
        role: gameUser.role,
        user_id: gameUser.user_id,
        email: gameUser.email,
        first_name: gameUser.first_name,
        last_name: gameUser.last_name,
      }
    });
  }
}

return results;

const previousNodeData = $input.all().map(item => item.json);
const importantFieldsData = $('GET IMPORTANT FIELDS').all().map(item => item.json);

const results = [];

previousNodeData.forEach(person => {
  const personOrgName = (person.organisation_name || '').toLowerCase().trim();

  // Get ALL matching games for this org
  const matches = importantFieldsData.filter(field => {
    const fieldOrgName = (field.organisation_name || '').toLowerCase().trim();
    return personOrgName === fieldOrgName;
  });

  if (matches.length > 0) {
    // Create one output item per game
    matches.forEach(match => {
      results.push({
        json: {
          organisation_name: person.organisation_name,
          game_name: match.game_name,
          source: match.source,
          url: match.url,
          externalId: person.externalId,
          email: person.email,
          name: person.name,
          role: person.role,
          hasFound: person.hasFound
        }
      });
    });
  } else {
    // No match — return person with nulls
    results.push({
      json: {
        organisation_name: person.organisation_name,
        game_name: null,
        source: null,
        url: null,
        externalId: person.externalId,
        email: person.email,
        name: person.name,
        role: person.role,
        hasFound: person.hasFound
      }
    });
  }
});

return results;

return items.map(item => {
  if (!item.json || !item.json.contact) {
    return {
      json: {
        organisation_name: "",
        email: "",
        name: "",
        role: "",
        _error: item.json?.error?.message || "Missing contact data"
      }
    };
  }
  const contact = item.json.contact;
  const accountContacts = item.json.accountContacts;
  const firstName = (contact.firstName || "").trim();
  const lastName = (contact.lastName || "").trim();
  const fullName = [firstName, lastName].filter(Boolean).join(" ");
  const jobTitle = Array.isArray(accountContacts) && accountContacts[0]?.jobTitle
    ? accountContacts[0].jobTitle.trim()
    : "";
  return {
    json: {
      organisation_name: (contact.orgname || "").trim(),
      email: (contact.email || "").trim().toLowerCase(),
      name: fullName,
      role: jobTitle,
    }
  };
});

const previousNodeData = $input.all().map(item => item.json);
const importantFieldsData = $('GET IMPORTANT FIELDS').all().map(item => item.json);

const normalize = (str) => (str || '').trim().toLowerCase();

// Deduplicate contacts by email + org (or just email if that's unique enough)
const seen = new Set();
const uniqueContacts = previousNodeData.filter(contact => {
  const key = `${normalize(contact.email)}|${normalize(contact.organisation_name)}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const results = [];

for (const contact of uniqueContacts) {
  const matches = importantFieldsData.filter(
    field => normalize(field.organisation_name) === normalize(contact.organisation_name)
  );

  if (matches.length > 0) {
    for (const match of matches) {
      results.push({
        json: {
          organisation_name: contact.organisation_name.trim(),
          game_name: match.game_name?.trim(),
          source: match.source?.trim(),
          url: match.url?.trim(),
          email: contact.email?.trim(),
          name: contact.name?.trim(),
          role: contact.role?.trim()
        }
      });
    }
  }
}

return results;

// Get all items from previous node (current input)
const previousNodeItems = $input.all();

// Get all items from "GET IMPORTANT FIELDS" node
const importantFieldsItems = $('GET IMPORTANT FIELDS').all();

// Extract the raw data arrays
const previousData = previousNodeItems.map(item => item.json);
const importantFields = importantFieldsItems.map(item => item.json);

const results = [];

for (const org of previousData) {
  const orgNameNormalized = (org.organisation_name || '').toLowerCase().trim();

  // Find all matching games from GET IMPORTANT FIELDS
  const matchingGames = importantFields.filter(field => {
    const fieldOrgNormalized = (field.organisation_name || '').toLowerCase().trim();
    return fieldOrgNormalized === orgNameNormalized;
  });

  if (matchingGames.length > 0) {
    // For each matching game, create a merged output item
    for (const game of matchingGames) {
      results.push({
        json: {
          organisation_name: org.organisation_name,
          hasFound: org.hasFound,
          source: org.source,
          game_name: game.game_name,
          game_source: game.source,
          url: game.url,
        }
      });
    }
  } else {
    // No match found — still return the org with nulls
    results.push({
      json: {
        organisation_name: org.organisation_name,
        hasFound: org.hasFound,
        source: org.source,
        game_name: null,
        game_source: null,
        url: null,
      }
    });
  }
}

return results;

